"use strict";(self.webpackChunkrgbds_www=self.webpackChunkrgbds_www||[]).push([[2930],{3742:(e,a,s)=>{s.r(a),s.d(a,{assets:()=>i,contentTitle:()=>r,default:()=>p,frontMatter:()=>o,metadata:()=>n,toc:()=>t});const n=JSON.parse('{"id":"rgbfix.1","title":"rgbfix(1) \u2014 Game Boy header utility and checksum fixer","description":"","source":"@site/versioned_docs/version-v0.9.4/rgbfix.1.md","sourceDirName":".","slug":"/rgbfix.1","permalink":"/docs/v0.9.4/rgbfix.1","draft":false,"unlisted":false,"editUrl":"https://github.com/gbdev/rgbds/edit/master/man/rgbfix.1","tags":[],"version":"v0.9.4","frontMatter":{},"sidebar":"nav","previous":{"title":"RGBLINK","permalink":"/docs/v0.9.4/rgblink.1"},"next":{"title":"RGBGFX","permalink":"/docs/v0.9.4/rgbgfx.1"}}');var l=s(74848),c=s(28453);const d='<section class="Sh">\n<h2 class="Sh" id="SYNOPSIS"><a class="permalink" href="#SYNOPSIS">SYNOPSIS</a></h2>\n<table class="Nm">\n  <tr>\n    <td><code class="Nm">rgbfix</code></td>\n    <td>[<code class="Fl"><a href="#h">-h</a><a href="#j">j</a><a href="#O">O</a><a href="#s">s</a><a href="#V">V</a><a href="#v">v</a><a href="#w">w</a></code>] [<code class="Fl"><a href="#C">-C</a></code> |\n      <code class="Fl"><a href="#c">-c</a></code>] [<code class="Fl"><a href="#f">-f</a></code>\n      <var class="Ar">fix_spec</var>] [<code class="Fl"><a href="#i">-i</a></code>\n      <var class="Ar">game_id</var>] [<code class="Fl"><a href="#k">-k</a></code>\n      <var class="Ar">licensee_str</var>] [<code class="Fl"><a href="#L">-L</a></code>\n      <var class="Ar">logo_file</var>] [<code class="Fl"><a href="#l">-l</a></code>\n      <var class="Ar">licensee_id</var>] [<code class="Fl"><a href="#m">-m</a></code>\n      <var class="Ar">mbc_type</var>] [<code class="Fl"><a href="#n">-n</a></code>\n      <var class="Ar">rom_version</var>] [<code class="Fl"><a href="#o">-o</a></code>\n      <var class="Ar">out_file</var>] [<code class="Fl"><a href="#p">-p</a></code>\n      <var class="Ar">pad_value</var>] [<code class="Fl"><a href="#r">-r</a></code>\n      <var class="Ar">ram_size</var>] [<code class="Fl"><a href="#t">-t</a></code>\n      <var class="Ar">title_str</var>] [<code class="Fl"><a href="#W">-W</a></code>\n      <var class="Ar">warning</var>] [<var class="Ar">file ...</var>]</td>\n  </tr>\n</table>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DESCRIPTION"><a class="permalink" href="#DESCRIPTION">DESCRIPTION</a></h2>\n<p class="Pp">The <code class="Nm">rgbfix</code> program changes headers of Game\n    Boy ROM images, typically generated by\n    <a class="Xr" href="./rgblink.1">rgblink(1)</a>, though it will work with\n    <a class="permalink" href="#any"><i class="Em" id="any">any</i></a> Game Boy\n    ROM. It also performs other correctness operations, such as padding.\n    <code class="Nm">rgbfix</code> only changes the fields for which it has\n    values specified. Developers are advised to fill those fields with 0x00\n    bytes in their source code before running <code class="Nm">rgbfix</code>,\n    and to have already populated whichever fields they don\'t specify using\n    <code class="Nm">rgbfix</code>.</p>\n<p class="Pp">The input <var class="Ar">asmfile</var> can be a path to a file,\n    or <code class="Cm">-</code> to read from standard input.</p>\n<p class="Pp">Note that options can be abbreviated as long as the abbreviation\n    is unambiguous: <code class="Fl">--color-o</code> is\n    <code class="Fl">--color-only</code>, but <code class="Fl">--color</code> is\n    invalid because it could also be <code class="Fl">--color-compatible</code>.\n    Options later in the command line override those set earlier. Accepted\n    options are as follows:</p>\n<dl class="Bl-tag">\n  <dt id="C"><a class="permalink" href="#C"><code class="Fl">-C</code></a>,\n    <code class="Fl">--color-only</code></dt>\n  <dd>Set the Game Boy Color&#x2013;only flag (<span class="Ad">0x143</span>) to\n      0xC0. This overrides <code class="Fl">-c</code> if it was set prior.</dd>\n  <dt id="c"><a class="permalink" href="#c"><code class="Fl">-c</code></a>,\n    <code class="Fl">--color-compatible</code></dt>\n  <dd>Set the Game Boy Color&#x2013;compatible flag:\n      (<span class="Ad">0x143</span>) to 0x80. This overrides\n      <code class="Fl">-c</code> if it was set prior.</dd>\n  <dt id="f"><a class="permalink" href="#f"><code class="Fl">-f</code></a>\n    <var class="Ar">fix_spec</var>, <code class="Fl">--fix-spec</code>\n    <var class="Ar">fix_spec</var></dt>\n  <dd>Fix certain header values that the Game Boy checks for correctness.\n      Alternatively, intentionally trash these values by writing their binary\n      inverse instead. <var class="Ar">fix_spec</var> is a string containing any\n      combination of the following characters:\n    <p class="Pp"></p>\n    <dl class="Bl-tag Bl-compact">\n      <dt id="l"><a class="permalink" href="#l"><code class="Cm">l</code></a></dt>\n      <dd>Fix the Nintendo logo\n          (<span class="Ad">0x104</span>&#x2013;<span class="Ad">0x133</span>).</dd>\n      <dt id="L"><a class="permalink" href="#L"><code class="Cm">L</code></a></dt>\n      <dd>Trash the Nintendo logo.</dd>\n      <dt id="h"><a class="permalink" href="#h"><code class="Cm">h</code></a></dt>\n      <dd>Fix the header checksum (<span class="Ad">0x14D</span>).</dd>\n      <dt id="H"><a class="permalink" href="#H"><code class="Cm">H</code></a></dt>\n      <dd>Trash the header checksum.</dd>\n      <dt id="g"><a class="permalink" href="#g"><code class="Cm">g</code></a></dt>\n      <dd>Fix the global checksum\n          (<span class="Ad">0x14E</span>&#x2013;<span class="Ad">0x14F</span>).</dd>\n      <dt id="G"><a class="permalink" href="#G"><code class="Cm">G</code></a></dt>\n      <dd>Trash the global checksum.</dd>\n    </dl>\n  </dd>\n  <dt id="h~2"><a class="permalink" href="#h~2"><code class="Fl">-h</code></a>,\n    <code class="Fl">--help</code></dt>\n  <dd>Print help text for the program and exit.</dd>\n  <dt id="i"><a class="permalink" href="#i"><code class="Fl">-i</code></a>\n    <var class="Ar">game_id</var>, <code class="Fl">--game-id</code>\n    <var class="Ar">game_id</var></dt>\n  <dd>Set the game ID string\n      (<span class="Ad">0x13F</span>&#x2013;<span class="Ad">0x142</span>) to a\n      given string. If it\'s longer than 4 characters, it will be truncated.</dd>\n  <dt id="j"><a class="permalink" href="#j"><code class="Fl">-j</code></a>,\n    <code class="Fl">--non-japanese</code></dt>\n  <dd>Set the non-Japanese region flag (<span class="Ad">0x14A</span>) to\n    0x01.</dd>\n  <dt id="k"><a class="permalink" href="#k"><code class="Fl">-k</code></a>\n    <var class="Ar">licensee_str</var>, <code class="Fl">--new-licensee</code>\n    <var class="Ar">licensee_str</var></dt>\n  <dd>Set the new licensee string\n      (<span class="Ad">0x144</span>&#x2013;<span class="Ad">0x145</span>) to a\n      given string. If it\'s longer than 2 characters, it will be truncated.</dd>\n  <dt id="L~2"><a class="permalink" href="#L~2"><code class="Fl">-L</code></a>\n    <var class="Ar">logo_file</var>, <code class="Fl">--logo</code>\n    <var class="Ar">logo_file</var></dt>\n  <dd>Specify a logo file to use instead of the official Nintendo logo. The file\n      must be 48 bytes of 1bpp tile data; the source image should be 48 pixels\n      wide and 8 pixels tall.</dd>\n  <dt id="l~2"><a class="permalink" href="#l~2"><code class="Fl">-l</code></a>\n    <var class="Ar">licensee_id</var>, <code class="Fl">--old-licensee</code>\n    <var class="Ar">licensee_id</var></dt>\n  <dd>Set the old licensee code (<span class="Ad">0x14B</span>) to a given value\n      from 0 to 0xFF. This value is deprecated and should be set to 0x33 in all\n      new software.</dd>\n  <dt id="m"><a class="permalink" href="#m"><code class="Fl">-m</code></a>\n    <var class="Ar">mbc_type</var>, <code class="Fl">--mbc-type</code>\n    <var class="Ar">mbc_type</var></dt>\n  <dd>Set the MBC type (<span class="Ad">0x147</span>) to a given value from 0\n      to 0xFF.\n    <p class="Pp">This value may also be an MBC name. The list of accepted names\n        can be obtained by passing\n        &#x2018;<code class="Li"><code class="Cm">help</code></code>&#x2019; or\n        &#x2018;<code class="Li"><code class="Cm">list</code></code>&#x2019; as\n        the argument. Any amount of whitespace (space and tabs) is allowed\n        around plus signs, and the order of &quot;components&quot; is free, as\n        long as the MBC name is first. There are special considerations to take\n        for the TPP1 mapper; see the <a class="Sx" href="#TPP1">TPP1</a> section\n        below.</p>\n  </dd>\n  <dt id="n"><a class="permalink" href="#n"><code class="Fl">-n</code></a>\n    <var class="Ar">rom_version</var>, <code class="Fl">--rom-version</code>\n    <var class="Ar">rom_version</var></dt>\n  <dd>Set the ROM version (<span class="Ad">0x14C</span>) to a given value from\n      0 to 0xFF.</dd>\n  <dt id="O"><a class="permalink" href="#O"><code class="Fl">-O</code></a>,\n    <code class="Fl">--overwrite</code></dt>\n  <dd>Alias for <code class="Fl">-Wno-overwrite</code>.</dd>\n  <dt id="o"><a class="permalink" href="#o"><code class="Fl">-o</code></a>\n    <var class="Ar">out_file</var>, <code class="Fl">--output</code>\n    <var class="Ar">out_file</var></dt>\n  <dd>Write the modified ROM image to the given file, or \'-\' to write to\n      standard output. If not specified, the input files are modified in-place,\n      or written to standard output if read from standard input.</dd>\n  <dt id="p"><a class="permalink" href="#p"><code class="Fl">-p</code></a>\n    <var class="Ar">pad_value</var>, <code class="Fl">--pad-value</code>\n    <var class="Ar">pad_value</var></dt>\n  <dd>Pad the ROM image to a valid size with a given pad value from 0 to 255\n      (0xFF). <code class="Nm">rgbfix</code> will automatically pick a size from\n      32 KiB, 64 KiB, 128 KiB, ..., 8192 KiB. The cartridge size byte\n      (<span class="Ad">0x148</span>) will be changed to reflect this new size.\n      The recommended padding value is 0xFF, to speed up writing the ROM to\n      flash chips, and to avoid &quot;nop slides&quot; into VRAM.</dd>\n  <dt id="r"><a class="permalink" href="#r"><code class="Fl">-r</code></a>\n    <var class="Ar">ram_size</var>, <code class="Fl">--ram-size</code>\n    <var class="Ar">ram_size</var></dt>\n  <dd>Set the RAM size (<span class="Ad">0x149</span>) to a given value from 0\n      to 0xFF.</dd>\n  <dt id="s"><a class="permalink" href="#s"><code class="Fl">-s</code></a>,\n    <code class="Fl">--sgb-compatible</code></dt>\n  <dd>Set the SGB flag (<span class="Ad">0x146</span>) to 0x03. This flag will\n      be ignored by the SGB unless the old licensee code\n      (<code class="Fl">--l</code>) is 0x33!</dd>\n  <dt id="t"><a class="permalink" href="#t"><code class="Fl">-t</code></a>\n    <var class="Ar">title</var>, <code class="Fl">--title</code>\n    <var class="Ar">title</var></dt>\n  <dd>Set the title string\n      (<span class="Ad">0x134</span>&#x2013;<span class="Ad">0x143</span>) to a\n      given string. If the title is longer than the maximum length, it will be\n      truncated. The max length is 11 characters if the game ID\n      (<code class="Fl">-i</code>) is specified, 15 characters if the CGB flag\n      (<code class="Fl">-c</code> or <code class="Fl">-C</code>) is specified\n      but the game ID is not, and 16 characters otherwise.</dd>\n  <dt id="V"><a class="permalink" href="#V"><code class="Fl">-V</code></a>,\n    <code class="Fl">--version</code></dt>\n  <dd>Print the version of the program and exit.</dd>\n  <dt id="v"><a class="permalink" href="#v"><code class="Fl">-v</code></a>,\n    <code class="Fl">--validate</code></dt>\n  <dd>Equivalent to <code class="Fl">-f</code> <code class="Cm">lhg</code>.</dd>\n  <dt id="W"><a class="permalink" href="#W"><code class="Fl">-W</code></a>\n    <var class="Ar">warning</var>, <code class="Fl">--warning</code>\n    <var class="Ar">warning</var></dt>\n  <dd>Set warning flag <var class="Ar">warning</var>. A warning message will be\n      printed if <var class="Ar">warning</var> is an unknown warning flag. See\n      the <a class="Sx" href="#DIAGNOSTICS">DIAGNOSTICS</a> section for a list\n      of warnings.</dd>\n  <dt id="w"><a class="permalink" href="#w"><code class="Fl">-w</code></a></dt>\n  <dd>Disable all warning output, even when turned into errors.</dd>\n</dl>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DIAGNOSTICS"><a class="permalink" href="#DIAGNOSTICS">DIAGNOSTICS</a></h2>\n<p class="Pp">Warnings are diagnostic messages that indicate possibly erroneous\n    behavior that does not necessarily compromise the header-fixing process. The\n    following options alter the way warnings are processed.</p>\n<dl class="Bl-tag">\n  <dt id="Werror"><a class="permalink" href="#Werror"><code class="Fl">-Werror</code></a></dt>\n  <dd>Make all warnings into errors. This can be negated as\n      <code class="Fl">-Wno-error</code> to prevent turning all warnings into\n      errors.</dd>\n  <dt id="Werror="><a class="permalink" href="#Werror="><code class="Fl">-Werror=</code></a></dt>\n  <dd>Make the specified warning or meta warning into an error. A warning\'s name\n      is appended (example: <code class="Fl">-Werror=overwrite</code>), and this\n      warning is implicitly enabled and turned into an error. This can be\n      negated as <code class="Fl">-Wno-error=</code> to prevent turning a\n      specified warning into an error, even if <code class="Fl">-Werror</code>\n      is in effect.</dd>\n</dl>\n<p class="Pp">The following warnings are &#x201C;meta&#x201D; warnings, that\n    enable a collection of other warnings. If a specific warning is toggled via\n    a meta flag and a specific one, the more specific one takes priority. The\n    position on the command-line acts as a tie breaker, the last one taking\n    effect.</p>\n<dl class="Bl-tag">\n  <dt id="Wall"><a class="permalink" href="#Wall"><code class="Fl">-Wall</code></a></dt>\n  <dd>This enables warnings that are likely to indicate an error or undesired\n      behavior, and that can easily be fixed.</dd>\n  <dt id="Weverything"><a class="permalink" href="#Weverything"><code class="Fl">-Weverything</code></a></dt>\n  <dd>Enables literally every warning.</dd>\n</dl>\n<p class="Pp">The following warnings are actual warning flags; with each\n    description, the corresponding warning flag is included. Note that each of\n    these flag also has a negation (for example,\n    <code class="Fl">-Wtruncation</code> enables the warning that\n    <code class="Fl">-Wno-truncation</code> disables; and\n    <code class="Fl">-Wall</code> enables every warning that\n    <code class="Fl">-Wno-all</code> disables). Only the non-default flag is\n    listed here. Ignoring the &#x201C;no-&#x201D; prefix, entries are listed\n    alphabetically.</p>\n<dl class="Bl-tag">\n  <dt id="Wno-mbc"><a class="permalink" href="#Wno-mbc"><code class="Fl">-Wno-mbc</code></a></dt>\n  <dd>Warn when there are inconsistencies with or caveats about the specified\n      MBC type.</dd>\n  <dt id="Wno-overwrite"><a class="permalink" href="#Wno-overwrite"><code class="Fl">-Wno-overwrite</code></a></dt>\n  <dd>Warn when overwriting different non-zero bytes in the header.</dd>\n  <dt id="Wno-sgb"><a class="permalink" href="#Wno-sgb"><code class="Fl">-Wno-sgb</code></a></dt>\n  <dd>Warn when the SGB flag (<code class="Fl">-s</code>) conflicts with the old\n      licensee code (<code class="Fl">-l</code>).</dd>\n  <dt id="Wno-truncation"><a class="permalink" href="#Wno-truncation"><code class="Fl">-Wno-truncation</code></a></dt>\n  <dd>Warn when truncating values to fit the available space.</dd>\n</dl>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="EXAMPLES"><a class="permalink" href="#EXAMPLES">EXAMPLES</a></h2>\n<p class="Pp">Most values in the ROM header do not matter to the actual console,\n    and most are seldom useful anyway. The bare minimum requirements for a\n    workable program are the header checksum, the Nintendo logo, and (if needed)\n    the CGB/SGB flags. It is a good idea to pad the image to a valid size as\n    well (&#x201C;valid&#x201D; meaning a power of 2, times 32 KiB).</p>\n<p class="Pp">The following will make a plain, non-color Game Boy game without\n    checking for a valid size:</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent">$ rgbfix -v foo.gb</div>\n<p class="Pp">The following will make a SGB-enabled, color-enabled game with a\n    title of &#x201C;foobar&#x201D;, and pad it to a valid size. (The Game Boy\n    itself does not use the title, but some emulators or ROM managers do.)</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent">$ rgbfix -vcs -l 0x33 -p 255 -t foobar baz.gb</div>\n<p class="Pp">The following will duplicate the header of the game\n    &#x201C;Survival Kids&#x201D;, sans global checksum:</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent">$ rgbfix -cjsv -k A4 -l 0x33 -m 0x1B -p 0xFF -r 3 -t\n  SURVIVALKIDAVKE SurvivalKids.gbc</div>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="TPP1"><a class="permalink" href="#TPP1">TPP1</a></h2>\n<p class="Pp">TPP1 is a homebrew mapper designed as a functional superset of the\n    common traditional MBCs, allowing larger ROM and RAM sizes combined with\n    other hardware features. Its specification, as well as more resources, can\n    be found online at\n    <a class="Lk" href="https://github.com/aaaaaa123456789/tpp1">https://github.com/aaaaaa123456789/tpp1</a>.</p>\n<section class="Ss">\n<h3 class="Ss" id="MBC_name"><a class="permalink" href="#MBC_name">MBC\n  name</a></h3>\n<p class="Pp">The MBC name for TPP1 is more complex than standard mappers. It\n    must be followed with the revision number, of the form\n    &#x2018;<code class="Li">major.minor</code>&#x2019;, where both\n    &#x2018;<code class="Li">major</code>&#x2019; and\n    &#x2018;<code class="Li">minor</code>&#x2019; are decimal, 8-bit integers.\n    There may be any amount of spaces or underscores between\n    &#x2018;<code class="Li">TPP1</code>&#x2019; and the revision number.\n    <code class="Nm">rgbfix</code> only supports 1.x revisions, and will reject\n    everything else.</p>\n<p class="Pp">Like other mappers, the name may be followed with a list of\n    optional, &#x2018;<code class="Li">+</code>&#x2019;-separated features;\n    however, &#x2018;<code class="Li">RAM</code>&#x2019; should not be\n    specified, as the TPP1 mapper implicitly requests RAM if a non-zero RAM size\n    is specified. Therefore, <code class="Nm">rgbfix</code> will ignore the\n    &#x2018;<code class="Li">RAM</code>&#x2019; feature on a TPP1 mapper.</p>\n</section>\n<section class="Ss">\n<h3 class="Ss" id="Special_considerations"><a class="permalink" href="#Special_considerations">Special\n  considerations</a></h3>\n<p class="Pp">TPP1 overwrites the byte at <span class="Ad">0x14A</span>, usually\n    indicating the region destination (see <code class="Fl">-j</code>), with one\n    of its three identification bytes. Therefore, <code class="Nm">rgbfix</code>\n    will warn about and ignore <code class="Fl">-j</code> if used in combination\n    with TPP1.</p>\n</section>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="BUGS"><a class="permalink" href="#BUGS">BUGS</a></h2>\n<p class="Pp">Please report bugs on\n    <a class="Lk" href="https://github.com/gbdev/rgbds/issues">GitHub</a>.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="SEE_ALSO"><a class="permalink" href="#SEE_ALSO">SEE\n  ALSO</a></h2>\n<p class="Pp"><a class="Xr" href="./rgbasm.1">rgbasm(1)</a>,\n    <a class="Xr" href="./rgblink.1">rgblink(1)</a>,\n    <a class="Xr" href="./rgbgfx.1">rgbgfx(1)</a>,\n    <a class="Xr" href="./gbz80.7">gbz80(7)</a>,\n    <a class="Xr" href="./rgbds.7">rgbds(7)</a></p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="HISTORY"><a class="permalink" href="#HISTORY">HISTORY</a></h2>\n<p class="Pp"><code class="Nm">rgbfix</code> was originally written by\n    <span class="An">Carsten S&#x00F8;rensen</span> as a standalone program\n    called GBFix, which was then packaged in ASMotor, and was later repackaged\n    in RGBDS by <span class="An">Justin Lloyd</span>. It is now maintained by a\n    number of contributors at\n    <a class="Lk" href="https://github.com/gbdev/rgbds">https://github.com/gbdev/rgbds</a>.</p>\n</section>\n',o={},r="rgbfix(1) \u2014 Game Boy header utility and checksum fixer",i={},t=[{value:"SYNOPSIS",id:"SYNOPSIS",level:2},{value:"DESCRIPTION",id:"DESCRIPTION",level:2},{value:"DIAGNOSTICS",id:"DIAGNOSTICS",level:2},{value:"EXAMPLES",id:"EXAMPLES",level:2},{value:"TPP1",id:"TPP1",level:2},{value:"MBC name",id:"MBC_name",level:3},{value:"Special considerations",id:"Special_considerations",level:3},{value:"BUGS",id:"BUGS",level:2},{value:"SEE ALSO",id:"SEE_ALSO",level:2},{value:"HISTORY",id:"HISTORY",level:2}];function h(e){const a={h1:"h1",header:"header",...(0,c.R)(),...e.components};return(0,l.jsxs)(l.Fragment,{children:[(0,l.jsx)(a.header,{children:(0,l.jsx)(a.h1,{id:"rgbfix1--game-boy-header-utility-and-checksum-fixer",children:"rgbfix(1) \u2014 Game Boy header utility and checksum fixer"})}),"\n","\n",(0,l.jsx)("div",{className:"manual-text",dangerouslySetInnerHTML:{__html:d}})]})}function p(e={}){const{wrapper:a}={...(0,c.R)(),...e.components};return a?(0,l.jsx)(a,{...e,children:(0,l.jsx)(h,{...e})}):h(e)}},28453:(e,a,s)=>{s.d(a,{R:()=>d,x:()=>o});var n=s(96540);const l={},c=n.createContext(l);function d(e){const a=n.useContext(c);return n.useMemo((function(){return"function"==typeof e?e(a):{...a,...e}}),[a,e])}function o(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(l):e.components||l:d(e.components),n.createElement(c.Provider,{value:a},e.children)}}}]);